module.render:
const color = args.color || 'var(--accent-color)';
const shapes = { rounded: '4px', square: '0', circle: '50%' };
const radius = shapes[String(args.shape || 'rounded').toLowerCase()] || '4px';
const sizes = { sm: '0.85em', md: '1em', lg: '1.2em' };
const size = sizes[String(args.size || 'md').toLowerCase()] || '1em';
const aligns = { left: 'left', center: 'center', right: 'right' };
const align = aligns[String(args.align || 'left').toLowerCase()] || 'left';
const contentStr = sections[0] ? sections[0].trim() : '';
return `\n\n<div class="mdp-mod-checklist" style="--checklist-mark: ${color}; --checklist-radius: ${radius}; font-size: ${size}; text-align: ${align};">\n\n${contentStr}\n\n</div>\n\n`;
